/**
 * These define how the browser should animate scrolling to an element.
 */
export const ScrollToAnimation = {
    /**
     * Default behavior. Scrolls immediately with no animation.
     * This is the standard, non-animated scrolling.
     */
    AUTO: 'auto',

    /**
     * Scrolls smoothly with a short animation.
     */
    SMOOTH: 'smooth',

    /**
     * Similar to 'auto', but may be treated differently by some browsers.
     */
    INSTANT: 'instant'
};
